// 1. 使用 flatMap 快速提取并展平所有数组
// item.json.snList || [] 表示如果 snList 不存在，就用空数组代替，防止报错
const allItems = $input.all().flatMap(item => item.json.snList || []);

// 2. 使用 Set 进行去重，然后转回数组
const uniqueList = [...new Set(allItems)];

return [
  {
    body: {
      snList: uniqueList,
    }
  }
];
